import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        // Build adjacency list
        Map<Long, List<long[]>> graph = new HashMap<>();
        for (long[] edge : edges) {
            long u = edge[0];
            long v = edge[1];
            long start = edge[2];
            long end = edge[3];
            graph.computeIfAbsent(u, k -> new ArrayList<>()).add(new long[]{v, start, end});
        }

        // Dijkstra's setup: priority queue sorted by arrival time
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[1]));
        pq.offer(new long[]{0, 0}); // {node, arrival_time}

        // Visited tracks the earliest arrival time for each node
        Map<Long, Long> visited = new HashMap<>();
        visited.put(0L, 0L);

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long node = current[0];
            long time = current[1];

            if (node == n - 1) {
                return time;
            }

            if (time > visited.getOrDefault(node, Long.MAX_VALUE)) {
                continue;
            }

            if (!graph.containsKey(node)) {
                continue;
            }

            for (long[] edge : graph.get(node)) {
                long nextNode = edge[0];
                long start = edge[1];
                long end = edge[2];

                // The earliest we can take this edge is max(time, start)
                long departureTime = Math.max(time, start);
                if (departureTime > end) {
                    continue; // Edge is no longer available
                }

                long arrivalTime = departureTime + 1;
                if (arrivalTime < visited.getOrDefault(nextNode, Long.MAX_VALUE)) {
                    visited.put(nextNode, arrivalTime);
                    pq.offer(new long[]{nextNode, arrivalTime});
                }
            }
        }

        return -1;
    }
}
